script:
(function() {
  var output = document.getElementById('terminal-output');
  output.innerHTML = '';
  var prideCanvas = document.getElementById('pride-matrix-canvas');
  if (!prideCanvas) {
    prideCanvas = document.createElement('canvas');
    prideCanvas.id = 'pride-matrix-canvas';
    prideCanvas.style.position = 'absolute';
    prideCanvas.style.top = 0;
    prideCanvas.style.left = 0;
    prideCanvas.style.width = '100%';
    prideCanvas.style.height = '100%';
    prideCanvas.style.pointerEvents = 'none';
    prideCanvas.style.zIndex = 10;
    output.appendChild(prideCanvas);
  }
  prideCanvas.width = output.offsetWidth;
  prideCanvas.height = output.offsetHeight;
  var colors = ['#e40303','#ff8c00','#ffed00','#008026','#004dff','#750787'];
  var words = ['LOVE', 'PRIDE', 'RESPECT', 'COMMUNITY'];
  var ctx = prideCanvas.getContext('2d');
  var fontSize = 18;
  var columns = Math.floor(prideCanvas.width / fontSize);
  var drops = Array(columns).fill(1);
  function draw() {
    ctx.fillStyle = 'rgba(10,10,10,0.15)';
    ctx.fillRect(0, 0, prideCanvas.width, prideCanvas.height);
    for (var i = 0; i < drops.length; i++) {
      var word = words[Math.floor(Math.random() * words.length)];
      ctx.font = fontSize + 'px monospace';
      ctx.fillStyle = colors[i % colors.length];
      ctx.fillText(word, i * fontSize, drops[i] * fontSize);
      if (Math.random() > 0.975) {
        drops[i] = 0;
      }
      drops[i]++;
    }
  }
  var prideAnim = setInterval(draw, 50);
  setTimeout(function() {
    clearInterval(prideAnim);
    if (prideCanvas && prideCanvas.parentNode) prideCanvas.parentNode.removeChild(prideCanvas);
  }, 10000);
})();
